84	  m.def(
85	      "writeBytecode",
86	      [](const nb::object &file_obj, const nb::object &moduleOp) -> bool {
87	        // Convert the Python object to MLIR module
88	        MlirOperation mlirOp = nb::cast<MlirOperation>(moduleOp);
89	
90	        // Platform-independent approach: write to memory buffer via CAPI,
91	        // then let Python handle file I/O
92	        MlirStringRef bytecode_buffer =
93	            mlirCudaTileWriteBytecodeToBuffer(mlirOp);
94	
95	        // Check for failure (empty buffer)
96	        if (bytecode_buffer.length == 0)
97	          return false;
98	
99	        // Write buffer to Python file object
100	        nb::bytes data(bytecode_buffer.data, bytecode_buffer.length);
101	        file_obj.attr("write")(data);
102	        if (nb::hasattr(file_obj, "flush"))
103	          file_obj.attr("flush")();
104	
105	        // Free the C-allocated buffer
106	        mlirCudaTileFreeBuffer(bytecode_buffer);
107	
108	        return true;
109	      },
110	      nb::arg("file"), nb::arg("module"),
111	      "Write cuda_tile module to bytecode file object using CAPI wrapper");
