194	      .def_classmethod(
195	          "get",
196	          [](const nb::object &cls, MlirType elementType,
197	             const std::vector<std::optional<int64_t>> &shape,
198	             const std::vector<std::optional<int64_t>> &stride,
199	             MlirContext context) -> nb::object {
200	            auto transformDynamic = [](std::optional<int64_t> val) {
201	              if (!val.has_value())
202	                return mlirCudaTileTensorViewTypeGetDynamicSize();
203	
204	              if (val.value() > 0)
205	                return val.value();
206	
207	              // Reject negative values early so kDynamic is not passed as is.
208	              std::string errorMsg;
209	              llvm::raw_string_ostream oss(errorMsg);
210	              oss << "expected strictly positive value for tensor_view "
211	                     "dimension, got "
212	                  << val.value();
213	              throw std::invalid_argument(errorMsg);
214	            };
215	
216	            std::vector<int64_t> shapeEncoded(shape.size());
217	            llvm::transform(shape, shapeEncoded.begin(), transformDynamic);
218	            std::vector<int64_t> strideEncoded(stride.size());
219	            llvm::transform(stride, strideEncoded.begin(), transformDynamic);
220	
221	            MlirType type = mlirCudaTileTensorViewTypeGetChecked(
222	                context, elementType, shape.size(), shapeEncoded.data(),
223	                stride.size(), strideEncoded.data());
224	            if (mlirTypeIsNull(type))
225	              return nb::none();
226	            return cls(type);
227	          },
228	          nb::arg("cls"), nb::arg("element_type"), nb::arg("shape"),
229	          nb::arg("stride"), nb::arg("context") = nb::none())
230	      .def_property_readonly("element_type",
