232	                               return mlirCudaTileTensorViewTypeGetElementType(
233	                                   type);
234	                             })
235	      .def_property_readonly(
236	          "shape",
237	          [](MlirType type) -> std::vector<std::optional<int64_t>> {
238	            intptr_t rank = mlirCudaTileTensorViewTypeGetRank(type);
239	            std::vector<std::optional<int64_t>> shapeOptional(rank);
240	            int64_t dynamicSize = mlirCudaTileTensorViewTypeGetDynamicSize();
241	            for (intptr_t i = 0; i < rank; ++i) {
242	              int64_t val = mlirCudaTileTensorViewTypeGetDimSize(type, i);
243	              shapeOptional[i] =
244	                  val == dynamicSize ? std::nullopt : std::optional{val};
245	            }
246	            return shapeOptional;
247	          })
248	      .def_property_readonly(
249	          "strides", [](MlirType type) -> std::vector<std::optional<int64_t>> {
250	            intptr_t rank = mlirCudaTileTensorViewTypeGetRank(type);
251	            std::vector<std::optional<int64_t>> strideOptional(rank);
252	            int64_t dynamicSize = mlirCudaTileTensorViewTypeGetDynamicSize();
253	            for (intptr_t i = 0; i < rank; ++i) {
254	              int64_t val = mlirCudaTileTensorViewTypeGetStride(type, i);
255	              strideOptional[i] =
256	                  val == dynamicSize ? std::nullopt : std::optional{val};
257	            }
258	            return strideOptional;
